class Solution {
public:
    vector<long long> unmarkedSumArray(vector<int>& nums, vector<vector<int>>& queries) {
        int n = nums.size();
        vector<int> marked(n, 0);
        long long sum = 0;
        for (int num : nums) sum += num;

        vector<pair<int, int>> indexedNums;
        for (int i = 0; i < n; ++i) {
            indexedNums.emplace_back(nums[i], i);
        }
        sort(indexedNums.begin(), indexedNums.end());

        int ptr = 0;
        vector<long long> ans;
        for (auto& query : queries) {
            int idx = query[0], k = query[1];
            if (!marked[idx]) {
                marked[idx] = 1;
                sum -= nums[idx];
            }

            while (k > 0 && ptr < n) {
                if (!marked[indexedNums[ptr].second]) {
                    sum -= indexedNums[ptr].first;
                    marked[indexedNums[ptr].second] = 1;
                    --k;
                }
                ++ptr;
            }
            ans.push_back(sum);
        }
        return ans;
    }
};
